mapper.select:
SELECT IFNULL(COUNT(*), 0) + 1 AS SEQ
  FROM pi_data_processing_charge_group
 WHERE user_no = #{user_no}
   AND DATE_FORMAT(REGDATE,'%Y%m%d') = #{today}

SELECT DP.hash_id, DP.TARGET_ID, TG.NAME, TG.CONNECTED_IP, DPG.idx AS CHARGE_ID, (SELECT processing_flag_name FROM pi_data_processing_flag WHERE processing_flag = DP.processing_flag) AS FLAG, DP.user_no, DPG.data_processing_name, F.PATH, CASE IFNULL(F.FID,'X') != 'X' WHEN 0 THEN 1 ELSE 0 END AS FID, DP.AP_NO AS AP_NO FROM PI_FIND AS F ,pi_data_processing_group AS DPG ,pi_data_processing AS DP LEFT OUTER JOIN PI_TARGET_GROUP TG ON TG.TARGET_ID = DP.TARGET_ID AND TG.AP_NO = DP.AP_NO AND TG.TYPE = 1 AND TG.TARGET_USE = 'Y' LEFT OUTER JOIN PI_TARGET_USER TU ON TG.TARGET_ID = TU.TARGET_ID AND TG.AP_NO = TU.AP_NO WHERE 1=1
AND TU.user_no = #{user_no}
AND DP.target_id = F.target_id AND DP.hash_id = F.hash_id AND DP.AP_NO = F.AP_NO AND DPG.idx = DP.data_processing_group_idx AND DPG.idx = #{data_processing_group_idx} GROUP BY DP.TARGET_ID ,DP.AP_NO, DP.HASH_ID ORDER BY DP.TARGET_ID ASC, DP.AP_NO

mapper.update:
UPDATE pi_data_processing_charge_group
   SET URL = #{url}
WHERE DATA_PROCESSING_CHARGE_ID = #{DATA_PROCESSING_CHARGE_ID}

UPDATE PI_DATA_PROCESSING_GROUP DPG
   SET DPG.APPROVAL_STATUS = #{apprType},
       DPG.data_processing_charge_id = #{data_processing_charge_id},
       DPG.NOTE = #{comment}
 WHERE DPG.USER_NO = #{user_no}
   AND DPG.IDX = #{idx}

UPDATE PI_DATA_PROCESSING DP
   SET DP.APPROVAL_STATUS = #{apprType}
 WHERE DP.USER_NO = #{user_no}
   AND DP.DATA_PROCESSING_GROUP_IDX = #{idx}

mapper.select:
SELECT DPG.idx AS CHARGE_ID, '' AS TARGET_ID, (SELECT NAME FROM pi_targets T WHERE T.TARGET_ID = DP.TARGET_ID) AS NAME, DPG.USER_NO, DPG.data_processing_name, (SELECT processing_flag_name FROM pi_data_processing_flag WHERE processing_flag = DPG.processing_flag) AS FLAG, GROUP_CONCAT(DISTINCT DP.hash_id SEPARATOR '\n') AS PATH, DPG.approval_status AS STATUS, DPG.reason AS REASON, DPG.REASON AS RETURN_REASON, '' AS FID FROM pi_data_processing DP, pi_data_processing_group DPG WHERE DPG.idx = DP.data_processing_group_idx AND DP.approval_type = 2 AND DPG.data_processing_charge_id IN
#{charge_id_list}
GROUP BY DPG.idx

SELECT idx AS GROUP_ID
  FROM PI_DATA_PROCESSING_GROUP
 WHERE data_processing_charge_id = #{chargeIdList}

mapper.update:
UPDATE PI_DATA_PROCESSING_CHARGE_GROUP DPC, PI_DATA_PROCESSING_GROUP DPG 
   SET DPC.APPROVAL_STATUS = #{apprType},
       DPG.APPROVAL_STATUS = #{apprType},

       DPC.reason = #{reason},
       DPG.reason = #{reason}



       DPC.reason = #{reason},
       DPG.reason = #{reason}

 WHERE DPC.data_processing_charge_id = #{chargeIdList}
   AND DPG.data_processing_charge_id = #{chargeIdList}

        UPDATE PI_DATA_PROCESSING_USER SET
			APPROVAL_STATUS = #{apprType},
			COMMENT = #{reason},
			OKDATE = NOW()
		WHERE OK_USER_NO = #{user_no}
			AND CHARGE_ID =#{chargeIdList}

        UPDATE PI_DATA_PROCESSING 
	       SET APPROVAL_STATUS = #{apprType}
	     WHERE data_processing_group_idx = #{group_id}

mapper.select:
SELECT D.TARGET_ID, D.NAME, COUNT(D.PROCESSING_FLAG) AS RESULT_CNT, D.PROCESSING_FLAG_NAME, D.HASH_ID, D.AP_NO FROM (SELECT DP.TARGET_ID, T.NAME, DP.DATA_PROCESSING_GROUP_IDX, DP.PROCESSING_FLAG, DF.PROCESSING_FLAG_NAME, DP.HASH_ID, DP.AP_NO FROM pi_data_processing AS DP, pi_targets T, pi_data_processing_flag DF WHERE 1 = 1 AND DP.data_processing_group_idx IN
#{item}
AND T.TARGET_ID = DP.TARGET_ID AND T.AP_NO = DP.AP_NO AND DF.PROCESSING_FLAG = DP.PROCESSING_FLAG) AS D GROUP BY D.TARGET_ID, D.AP_NO, D.PROCESSING_FLAG, D.HASH_ID ORDER BY D.TARGET_ID, D.AP_NO

SELECT CHARGE_ID, CHARGE_USER_CNT, CU.NAME AS CHARGE_USER_FLAGE, DPU.USER_NO, OK_USER_NO, U.USER_NAME, COMMENT, APPROVAL_STATUS FROM PI_DATA_PROCESSING_USER DPU LEFT OUTER JOIN pi_custom_name CU ON DPU.CHARGE_USER_FLAGE = CONCAT(CU.flag, '_', CU.idx ) AND FLAG = 'approval' LEFT OUTER JOIN PI_USER U ON U.USER_NO = DPU.OK_USER_NO WHERE DPU.CHARGE_ID IN
#{charge_id_list}
AND DPU.CHARGE_USER_CNT != 'Y' ORDER BY DPU.CHARGE_USER_CNT

