SELECT DP.DATA_PROCESSING_GROUP_IDX, DP.PROCESSING_FLAG, DF.PROCESSING_FLAG_NAME, DP.HASH_ID, DP.AP_NO, IFNULL(DP.NOTEPAD, '') AS NOTEPAD FROM pi_data_processing_flag DF, pi_data_processing DP WHERE 1 = 1 AND DP.data_processing_group_idx IN
#{item}
AND DP.approval_type = '2' AND DF.PROCESSING_FLAG = DP.PROCESSING_FLAG GROUP BY DP.HASH_ID ORDER BY DP.DATA_PROCESSING_GROUP_IDX, DP.TARGET_ID, DP.AP_NO
